import{_ as a,o,c as p,a5 as l}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"教程 0003：脉宽调制（pulse-width modulation / PWM）与模数转换器采样（analog-to-digital converter / ADC sampling）","description":"","frontmatter":{"title":"教程 0003：脉宽调制（pulse-width modulation / PWM）与模数转换器采样（analog-to-digital converter / ADC sampling）","date":"2026-07-01T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0003-pwm-sampling.html","status":"learning","visibility":"public","summary":"Imported from 0003-pwm-sampling.html","chapterTitle":"电源课程","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0003-pwm-sampling.md","filePath":"content/power/lessons/0003-pwm-sampling.md","lastUpdated":1782999393000}'),i={name:"content/power/lessons/0003-pwm-sampling.md"};function t(s,e,n,r,d,c){return o(),p("div",null,[...e[0]||(e[0]=[l(`<h1 id="教程-0003-脉宽调制-pulse-width-modulation-pwm-与模数转换器采样-analog-to-digital-converter-adc-sampling" tabindex="-1">教程 0003：脉宽调制（pulse-width modulation / PWM）与模数转换器采样（analog-to-digital converter / ADC sampling） <a class="header-anchor" href="#教程-0003-脉宽调制-pulse-width-modulation-pwm-与模数转换器采样-analog-to-digital-converter-adc-sampling" aria-label="Permalink to &quot;教程 0003：脉宽调制（pulse-width modulation / PWM）与模数转换器采样（analog-to-digital converter / ADC sampling）&quot;">​</a></h1><p>中文主讲。一个概念：把 PWM 更新、开关状态、电感电流纹波和 ADC 采样点放在同一条时间线上，为后续阅读 C 语言控制中断代码打基础。</p><pre><code>本页学习顺序
</code></pre><ul><li><p>理解 PWM 和 ADC 采样分别做什么。</p></li><li><p>用 Boost 电感电流纹波理解“为什么采样时刻重要”。</p></li><li><p>掌握开关周期、导通时间和采样相位三个公式。</p></li><li><p>运行一个仿真任务，看采样点落在电流纹波的哪里。</p></li><li><p>把问题转换成可以问导师的具体代码阅读问题。</p></li></ul><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>脉宽调制（pulse-width modulation / PWM）是用固定开关频率下的导通时间比例来控制功率开关。这个比例叫占空比（duty cycle / D）。</p><p>模数转换器采样（analog-to-digital converter / ADC sampling）是把电压、电流等模拟量在某个时刻转换成数字量，交给控制中断服务程序（control interrupt service routine / control ISR）计算下一次控制输出。</p><pre><code>一句话记忆：PWM 决定功率级什么时候切换，ADC 决定固件在什么时候“看见”功率级。
</code></pre><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）控制软件不是连续观察电路，而是在固定时刻采样，再在固定中断里计算。</p><pre><code>控制准确性
</code></pre><p>采样点如果落在开关噪声上，控制器拿到的电流值会偏离真实趋势。 保护判断 过流、欠压、采样异常都依赖 ADC 值，采样时刻会影响误报和漏报。 读 C 工程 后续看代码时，要能追踪 PWM 触发、ADC 转换和控制 ISR 的调用顺序。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>Boost 开关导通时，电感电流上升；开关关断时，电感电流下降。所以电感电流不是一条平滑平均线，而是一条带开关纹波的三角形或近似三角形曲线。</p><p>ADC 如果刚好在开关跳变附近采样，就容易采到尖峰、振铃或驱动噪声。工程上常把采样点放在相对安静的位置，例如关断后经过一小段延时，或者电流纹波较稳定的位置。</p><p>这不是“采样越快越好”的问题，而是“在正确时刻采样”的问题。</p><pre><code>载波
开关
电流

ADC采样点
</code></pre><p>图 1：同一开关周期内，PWM 决定开关状态，ADC 采样点决定固件读到电流纹波的哪个位置。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>开关周期：</p><p>Ts = 1 / fsw</p><p>导通时间：</p><p>Ton = D * Ts</p><p>采样时刻：</p><p>t_sample = (n + sample_phase) * Ts + sample_delay</p><p>其中 <code>fsw</code> 是开关频率（switching frequency），<code>sample_phase</code> 是采样相位，<code>sample_delay</code> 是采样延迟。比如 <code>sample_phase = 0.8</code> 表示每个周期 80% 位置采样。</p><pre><code>不要只看采样频率。同样是 20 kHz 采样，采在开关边沿和采在安静区间，控制效果可能完全不同。
</code></pre><h2 id="_5-一个仿真任务" tabindex="-1">5. 一个仿真任务 <a class="header-anchor" href="#_5-一个仿真任务" aria-label="Permalink to &quot;5. 一个仿真任务&quot;">​</a></h2><p>在 PowerShell 中运行：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\boost_pwm_sampling.py</p><p>脚本会自动打开结果图；如果打不开，会打印完整路径。默认结果图路径：<code>simulations/results/boost_pwm_sampling.png</code>。图中包含参数框、图例、PWM 载波、占空比命令、开关状态、电感电流和 ADC 采样点。</p><pre><code>对比实验：移动采样点
python simulations\\python\\boost_pwm_sampling.py --sample-phase 0.2 --output simulations\\results\\boost_pwm_sampling_phase_02.png
</code></pre><p>python simulations\\python\\boost_pwm_sampling.py --sample-phase 0.8 --output simulations\\results\\boost_pwm_sampling_phase_08.png python simulations\\python\\boost_pwm_sampling.py --sample-phase 0.8 --sample-delay 5e-6 --output simulations\\results\\boost_pwm_sampling_delay_5us.png</p><p>观察采样点落在电感电流上升段、下降段还是靠近开关边沿。不要只看采样值大小，要看它对应的时刻。</p><h2 id="_6-仿真观察" tabindex="-1">6. 仿真观察 <a class="header-anchor" href="#_6-仿真观察" aria-label="Permalink to &quot;6. 仿真观察&quot;">​</a></h2><ul><li><p>先看第一幅子图：载波和占空比命令的交点决定开关翻转。</p></li><li><p>再看第二幅子图：开关状态为 1 时，Boost 电感电流上升。</p></li><li><p>最后看第三幅子图：红点是 ADC 采样点，红色竖线帮你对齐采样时刻。</p></li><li><p>比较 <code>--sample-phase 0.2</code> 和 <code>--sample-phase 0.8</code>，说明采样点为什么会落在不同纹波位置。</p></li></ul><h2 id="_7-固件落地" tabindex="-1">7. 固件落地 <a class="header-anchor" href="#_7-固件落地" aria-label="Permalink to &quot;7. 固件落地&quot;">​</a></h2><p>在 C 语言固件里，PWM/ADC timing 通常分散在几个模块：</p><ul><li><p>PWM 初始化：设置频率、计数模式、比较值和更新事件。</p></li><li><p>ADC 初始化：设置触发源、采样通道、采样时间和转换序列。</p></li><li><p>控制 ISR：读取 ADC 结果，计算控制器，更新下一周期 PWM 占空比。</p></li><li><p>保护逻辑：判断采样值是否越界，必要时关断 PWM 或进入故障状态。</p></li></ul><p>读代码时要追问：这个 ADC 值对应的是哪个 PWM 周期、哪个相位、哪个物理量？</p><h2 id="_8-常见误解" tabindex="-1">8. 常见误解 <a class="header-anchor" href="#_8-常见误解" aria-label="Permalink to &quot;8. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**ADC 采样越快越好。 **纠正：**采样频率和采样相位都重要。采在开关噪声上，快也没用。</p></li><li><p>**误解：**PWM 占空比一更新，输出马上按新值变化。 **纠正：**很多定时器有影子寄存器（shadow register），新占空比要等更新事件才生效。</p></li><li><p>**误解：**控制 ISR 里读到的电流就是连续真实电流。 **纠正：**它是某个采样时刻的离散值，带有采样延迟、滤波延迟和量化误差。</p></li><li><p>**误解：**仿真只画平均值就够了。 **纠正：**采样点和开关纹波的位置关系，必须看时序图才能理解。</p></li></ul><h2 id="_9-验收标准" tabindex="-1">9. 验收标准 <a class="header-anchor" href="#_9-验收标准" aria-label="Permalink to &quot;9. 验收标准&quot;">​</a></h2><ul><li><p>能解释 PWM、ADC、控制 ISR 三者的先后关系。</p></li><li><p>能用 <code>Ts = 1 / fsw</code> 和 <code>Ton = D * Ts</code> 计算周期和导通时间。</p></li><li><p>能在仿真图上指出 ADC 采样点落在电感电流纹波的哪个位置。</p></li><li><p>能解释为什么采在开关边沿附近可能不可靠。</p></li><li><p>能把仿真图转换成一个具体的 C 工程代码阅读问题。</p></li></ul><h2 id="_10-复盘问题" tabindex="-1">10. 复盘问题 <a class="header-anchor" href="#_10-复盘问题" aria-label="Permalink to &quot;10. 复盘问题&quot;">​</a></h2><ul><li><p>打开 <code>simulations/results/boost_pwm_sampling.png</code>，红色 ADC 采样点落在电感电流的上升段还是下降段？</p></li><li><p>如果 <code>fsw = 20 kHz</code>，一个开关周期是多少微秒？<code>D = 0.45</code> 时导通时间是多少微秒？</p></li><li><p>如果把采样点放在开关翻转边沿附近，固件可能读到什么问题？</p></li></ul><h2 id="_11-导师问题" tabindex="-1">11. 导师问题 <a class="header-anchor" href="#_11-导师问题" aria-label="Permalink to &quot;11. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>boost_pwm_sampling.py --sample-phase 0.8</code> 看到 ADC 采样点在周期后段。公司 Boost 或功率因数校正（power factor correction / PFC）电流采样通常放在 PWM 周期的哪个相位，原因是什么？</p></li><li><p>如果控制 ISR 读取的是上一个 PWM 周期的 ADC 结果，公司代码里通常如何标注或处理这个一拍延迟？</p></li><li><p>公司平台的 PWM 占空比更新是立即生效，还是通过影子寄存器在更新事件生效？我应该从哪个初始化文件确认？</p></li></ul><p>**下一步：**完成这节后，记录默认图中的采样时刻和采样电流值。下一节仍围绕 Boost，进入离散比例积分控制器（discrete proportional-integral controller / discrete PI）的最小闭环雏形。</p><p>关联：<a href="./0002-ccm-dcm.html">上一节：连续导通模式与断续导通模式</a>；源稿：<code>concepts/power-electronics/pwm-sampling.md</code>。</p><pre><code>上一节：教程 0002：连续导通模式（continuous conduction mode / CCM）与断续导通模式（discontinuous conduction mode / DCM）
下一节：教程 0004：离散比例积分控制器（discrete proportional-integral controller / discrete PI）最小闭环
</code></pre>`,51)])])}const u=a(i,[["render",t]]);export{h as __pageData,u as default};
